def test_enforce_headers(enforce_headers):
    # Test None returns empty list (catches none_returns_nonempty and none_check_flipped)
    assert enforce_headers(None, name="test") == []

    # Test mapping branch returns correct (key, value) order (catches mapping_swap_key_value)
    headers_map = {b"key1": b"value1", "key2": "value2"}
    result = enforce_headers(headers_map, name="test")
    expected = [(b"key1", b"value1"), (b"key2", b"value2")]
    assert result == expected

    # Test sequence branch works and does not fall through to TypeError (catches drop_sequence_branch)
    headers_seq = [(b"key1", b"value1"), ("key2", "value2")]
    result = enforce_headers(headers_seq, name="test")
    expected = [(b"key1", b"value1"), (b"key2", b"value2")]
    assert result == expected

    # Test header value non-ASCII raises with correct name (catches wrong_name_constant)
    try:
        enforce_headers({b"key": "val\u00e9"}, name="test")
    except TypeError as e:
        assert "header value" in str(e)
    else:
        assert False, "Expected TypeError for non-ASCII header value"

    # Test header name non-ASCII raises with correct name (ensures name parameter is used correctly)
    try:
        enforce_headers({"k\u00e9y": b"value"}, name="test")
    except TypeError as e:
        assert "header name" in str(e)
    else:
        assert False, "Expected TypeError for non-ASCII header name"

    # Test invalid type raises TypeError with appropriate message
    try:
        enforce_headers(123, name="test")
    except TypeError as e:
        assert "must be a mapping or sequence of two-tuples" in str(e)
    else:
        assert False, "Expected TypeError for invalid type"

